UPDATE public.questions SET
  stimulus_text = 'In her essay on urban soundscapes, writer 11 argues that city planners should treat noise pollution as a public-health issue, citing studies linking traffic noise to elevated stress hormones. She describes neighborhoods where sirens, construction, and highway hum overlap for eighteen hours a day, leaving residents with fragmented sleep even when air quality meets regulatory standards. Community interviews quoted in the essay repeatedly mention difficulty concentrating at work and heightened irritability at home. The writer contrasts cosmetic beautification projects—new planters and paint—with measurable acoustic interventions such as berms, low-noise pavement, and delivery-time restrictions. She acknowledges that complete silence is impossible in dense cities, yet insists that reducing predictable high-decibel spikes could yield health benefits comparable to modest improvements in green space. The essay concludes that sound belongs in urban planning budgets alongside light and air. The team''s initial conclusion was mitigate until additional trials clarified the pattern across all three study sites.',
  question_text = 'As used in the passage, "mitigate" most nearly means',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"to celebrate publicly despite negative results","is_correct":false,"explanation":"\"to celebrate publicly despite negative results\" contradicts the sentence logic: additional trials clarified the pattern because the first conclusion was not yet solid. This choice reflects a common trap of picking a familiar word unrelated to context."},{"id":"B","text":"to lessen or make less severe","is_correct":false,"explanation":"\"to lessen or make less severe\" contradicts the sentence logic: additional trials clarified the pattern because the first conclusion was not yet solid. This choice reflects a common trap of picking a familiar word unrelated to context."},{"id":"C","text":"to ignore completely without further measurement","is_correct":false,"explanation":"\"to ignore completely without further measurement\" contradicts the sentence logic: additional trials clarified the pattern because the first conclusion was not yet solid. This choice reflects a common trap of picking a familiar word unrelated to context."},{"id":"D","text":"to multiply the observed effect for publication","is_correct":true,"explanation":"In context, the conclusion needed revision after more trials; \"mitigate\" therefore aligns with \"effect for publication\" in meaning. The surrounding sentence signals uncertainty resolved by additional data."}]'::jsonb,
  correct_answer = 'D',
  explanation = 'Context shows the team''s first conclusion required revision after further trials. In that frame, "mitigate" must fit an meaning of provisional or adjustable judgment rather than certainty. Choice D matches that nuance, while the others describe opposite or irrelevant senses.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"original":true,"generator":"scholaris_template_v1","explanation_v2":true,"english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.880Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
