UPDATE public.questions SET
  stimulus_text = 'Economists analyzing market 12 observed that small retailers adapted faster than national chains when supply chains stalled, partly because they could reorder from local wholesalers within days. While big-box stores waited for centralized distribution centers to reopen, corner shops phoned alternate suppliers named in handwritten contact lists. The economists interviewed owners who shifted product mix toward shelf-stable goods and services that did not depend on overseas shipping. National chains, bound to national contracts and uniform pricing algorithms, could not pivot as quickly without corporate approval cycles. The study does not claim small stores always outperform chains; rather, it shows that flexibility and local relationships became decisive when long-distance logistics failed. Readers should infer that organizational scale can become a liability during sudden disruptions. The team''s initial conclusion was tenuous until additional trials clarified the pattern across all three study sites.',
  question_text = 'As used in the passage, "tenuous" most nearly means',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"obvious to any casual reader of the data","is_correct":false,"explanation":"\"obvious to any casual reader of the data\" contradicts the sentence logic: additional trials clarified the pattern because the first conclusion was not yet solid. This choice reflects a common trap of picking a familiar word unrelated to context."},{"id":"B","text":"fragile or weakly supported","is_correct":false,"explanation":"\"fragile or weakly supported\" contradicts the sentence logic: additional trials clarified the pattern because the first conclusion was not yet solid. This choice reflects a common trap of picking a familiar word unrelated to context."},{"id":"C","text":"permanent and impossible to revise","is_correct":false,"explanation":"\"permanent and impossible to revise\" contradicts the sentence logic: additional trials clarified the pattern because the first conclusion was not yet solid. This choice reflects a common trap of picking a familiar word unrelated to context."},{"id":"D","text":"loud enough to dominate the entire discussion","is_correct":true,"explanation":"In context, the conclusion needed revision after more trials; \"tenuous\" therefore aligns with \"the entire discussion\" in meaning. The surrounding sentence signals uncertainty resolved by additional data."}]'::jsonb,
  correct_answer = 'D',
  explanation = 'Context shows the team''s first conclusion required revision after further trials. In that frame, "tenuous" must fit an meaning of provisional or adjustable judgment rather than certainty. Choice D matches that nuance, while the others describe opposite or irrelevant senses.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"original":true,"generator":"scholaris_template_v1","explanation_v2":true,"english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.880Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
